import React from 'react';
import '../styles/Footer.css';

const Footer = () => {
  return (
    <footer className="footer-container">
      <div className="footer-content">
        
        {/* Column 1: Logo & Tagline */}
        <div className="footer-column">
          <h2 className="footer-logo"><span className="blue-text">PAU Connect</span></h2>
          <p>Connecting the next generation of professionals with the world's leading companies.</p>
        </div>

        {/* Column 2: Quick Links */}
        <div className="footer-column">
          <h3>Quick Links</h3>
          <ul>
            <li><a href="/FindJobs">Find Jobs</a></li>
            <li><a href="/PostJob">Post a Job</a></li>
            <li><a href="/About">About Us</a></li>
          </ul>
        </div>

        {/* Column 3: Contact Us */}
        <div className="footer-column">
          <h3>Contact Us</h3>
          <p>Email: info@pauconnect.edu</p>
          <p>Phone: +234 123 456 7890</p>
          <div className="social-icons">
             {/* You can add icons here later */}
             <span>FB</span> <span>TW</span> <span>IG</span>
          </div>
        </div>

      </div>
      
      <div className="footer-bottom">
        <p>© 2026 PAU Connect. All rights reserved.</p>
      </div>
    </footer>
  );
};

export default Footer;
